import{_ as o,o as t,c as i,ag as n}from"./chunks/framework.BqfgOMAh.js";const h=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"en/faq/troubleshooting.md","filePath":"en/faq/troubleshooting.md"}'),s={name:"en/faq/troubleshooting.md"};function a(r,e,l,c,d,g){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>This page provides detailed diagnostic steps for common issues. For quick answers, check the <a href="./">FAQ</a> first.</p><h2 id="cannot-connect-to-ue-editor" tabindex="-1">Cannot Connect to UE Editor <a class="header-anchor" href="#cannot-connect-to-ue-editor" aria-label="Permalink to &quot;Cannot Connect to UE Editor&quot;">​</a></h2><p><strong>Symptom</strong>: The NexusFlow status bar stays 🔴 red (disconnected), even though the UE Editor is running.</p><p><strong>Possible causes</strong>:</p><ul><li>Version mismatch between the NexusFlow desktop app and UE plugin</li><li>NexusFlow plugin is not enabled in the UE project</li><li>Firewall or security software blocking communication</li><li>Another NexusFlow instance is occupying the communication pipe</li></ul><p><strong>Diagnostic steps</strong>:</p><ol><li><strong>Check version compatibility</strong>: Make sure both the NexusFlow desktop app and UE plugin are updated to the latest version. Version mismatches are the most common cause of connection failures</li><li><strong>Check plugin status</strong>: In UE, go to Edit &gt; Plugins, search for &quot;NexusFlow,&quot; and confirm the plugin is enabled</li><li><strong>Rule out firewall interference</strong>: Temporarily disable your firewall or security software and test the connection</li><li><strong>Check for multiple instances</strong>: Make sure only one NexusFlow process is running (check Task Manager)</li><li><strong>Review logs</strong>: <ul><li>NexusFlow log: <code>%APPDATA%/cn.nexusflow.desktop/logs/tauri_debug.log</code></li><li>UE log: In <code>&lt;Project Directory&gt;/Saved/Logs/</code>, search for <code>LogNexusFlow</code></li></ul></li><li><strong>Restart both applications</strong>: Close UE and NexusFlow, then relaunch them (startup order does not matter)</li></ol><div class="tip custom-block"><p class="custom-block-title">Quick check</p><p>Open NexusFlow&#39;s Settings &gt; About page and look at the &quot;Plugin Status&quot; section to see if a UE installation is detected.</p></div><h2 id="ai-not-responding-or-showing-errors" tabindex="-1">AI Not Responding or Showing Errors <a class="header-anchor" href="#ai-not-responding-or-showing-errors" aria-label="Permalink to &quot;AI Not Responding or Showing Errors&quot;">​</a></h2><p><strong>Symptom</strong>: After sending a message, the AI doesn&#39;t reply, or the chat area displays an error.</p><p><strong>Possible causes</strong>:</p><ul><li>No AI model configured, or validation has failed</li><li>Invalid API Key or insufficient account balance</li><li>Network cannot reach the AI provider&#39;s endpoint</li><li>Custom Provider is misconfigured</li></ul><p><strong>Diagnostic steps</strong>:</p><ol><li><strong>Check model configuration</strong>: Go to Settings &gt; AI Models and confirm at least one model is added and set as default</li><li><strong>Test the model connection</strong>: Click the &quot;Validate&quot; button on the model card</li><li><strong>If validation fails</strong>: <ul><li>Verify the API Key is copied correctly (watch for leading/trailing spaces)</li><li>Confirm your provider account has sufficient balance</li><li>Test network connectivity: <ul><li>OpenAI: Can you reach <code>api.openai.com</code>?</li><li>Anthropic: Can you reach <code>api.anthropic.com</code>?</li><li>DeepSeek: Can you reach <code>api.deepseek.com</code>?</li><li>Zhipu GLM: Can you reach <code>open.bigmodel.cn</code>?</li><li>MiniMax: Can you reach <code>api.minimaxi.com</code>?</li><li>Qwen: Can you reach <code>dashscope.aliyuncs.com</code>?</li><li>Kimi: Can you reach <code>api.moonshot.cn</code>?</li></ul></li></ul></li><li><strong>If using a Custom Provider</strong>: Confirm the API URL and communication protocol are correct</li><li><strong>Check logs</strong>: Open <code>%APPDATA%/cn.nexusflow.desktop/logs/tauri_debug.log</code> and search for <code>error</code> or <code>failed</code></li></ol><div class="warning custom-block"><p class="custom-block-title">Anthropic users</p><p>Anthropic (Claude) models <strong>require</strong> Max Tokens to be set. Without it, API calls will fail. Check your model configuration.</p></div><h2 id="sidebar-chat-unavailable-for-a-long-time" tabindex="-1">Sidebar Chat Unavailable for a Long Time <a class="header-anchor" href="#sidebar-chat-unavailable-for-a-long-time" aria-label="Permalink to &quot;Sidebar Chat Unavailable for a Long Time&quot;">​</a></h2><p><strong>Symptom</strong>: After opening the sidebar, the chat input remains disabled or shows a loading state for an extended period.</p><p><strong>Possible causes</strong>:</p><ul><li>Internal AI service initialization delay</li><li>Port conflict with another NexusFlow instance or another program</li></ul><p><strong>Diagnostic steps</strong>:</p><ol><li><strong>Wait for initialization</strong>: On first launch, the AI service needs roughly 10 seconds to initialize and will retry automatically</li><li><strong>Check for multiple instances</strong>: Search for &quot;NexusFlow&quot; in Task Manager and close any extra instances</li><li><strong>Check for port conflicts</strong>: Another program may have claimed the port</li><li><strong>Restart the application</strong>: Fully close NexusFlow and relaunch it</li></ol><h2 id="blueprint-behaves-abnormally-after-ai-operation" tabindex="-1">Blueprint Behaves Abnormally After AI Operation <a class="header-anchor" href="#blueprint-behaves-abnormally-after-ai-operation" aria-label="Permalink to &quot;Blueprint Behaves Abnormally After AI Operation&quot;">​</a></h2><p><strong>Symptom</strong>: After the AI modifies a Blueprint, compilation errors appear, connections are broken, or behavior is unexpected.</p><p><strong>Possible causes</strong>:</p><ul><li>AI-generated operations aren&#39;t always perfect</li><li>Invalid connections or missing required nodes may be produced</li><li>Complex Blueprints may not be handled with full precision</li></ul><p><strong>Diagnostic steps</strong>:</p><ol><li><strong>Undo immediately</strong>: Press <code>Ctrl+Z</code> in UE to undo the most recent operation</li><li><strong>Check error messages</strong>: Review the Blueprint compiler&#39;s error output for specifics</li><li><strong>Undo multiple times</strong>: If one undo isn&#39;t enough, press <code>Ctrl+Z</code> several times to roll back further</li><li><strong>Restore from version control</strong>: If undo doesn&#39;t help, revert the file via Git or another VCS</li></ol><div class="danger custom-block"><p class="custom-block-title">Important</p><p>Before letting the AI make significant Blueprint changes, <strong>save the Blueprint</strong> (<code>Ctrl+S</code>). That way you can always undo back to the save point if something goes wrong.</p></div><p><strong>Prevention tips</strong>:</p><ul><li>Save important Blueprints before AI operations</li><li>Use a version control system (e.g., Git) to manage Blueprint files</li><li>Break large tasks into smaller steps instead of executing many changes at once</li><li>Be as specific as possible when describing what you need</li></ul><h2 id="global-hotkeys-not-working" tabindex="-1">Global Hotkeys Not Working <a class="header-anchor" href="#global-hotkeys-not-working" aria-label="Permalink to &quot;Global Hotkeys Not Working&quot;">​</a></h2><p><strong>Symptom</strong>: A global hotkey (e.g., toggle sidebar) has been set but doesn&#39;t respond when pressed.</p><p><strong>Possible causes</strong>:</p><ul><li>Hotkey conflicts with another application</li><li>Hotkey failed to register with the operating system</li><li>Application wasn&#39;t restarted after the change</li></ul><p><strong>Diagnostic steps</strong>:</p><ol><li><strong>Check for conflicts</strong>: Make sure no other application (screenshot tool, input method, etc.) is using the same key combination</li><li><strong>Try a different combination</strong>: Go to Settings &gt; Hotkeys and pick a less common shortcut</li><li><strong>Reset to default</strong>: Click the &quot;Reset to Default&quot; button to restore all hotkeys</li><li><strong>Restart the application</strong>: <strong>Restart NexusFlow</strong> after changing hotkeys for them to take effect</li></ol><h2 id="log-file-locations" tabindex="-1">Log File Locations <a class="header-anchor" href="#log-file-locations" aria-label="Permalink to &quot;Log File Locations&quot;">​</a></h2><p>Log files are the most valuable source of diagnostic information when troubleshooting.</p><h3 id="nexusflow-logs" tabindex="-1">NexusFlow Logs <a class="header-anchor" href="#nexusflow-logs" aria-label="Permalink to &quot;NexusFlow Logs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Log</th><th>Path</th></tr></thead><tbody><tr><td>Main application log</td><td><code>%APPDATA%/cn.nexusflow.desktop/logs/tauri_debug.log</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Opening the AppData directory</p><p>Type <code>%APPDATA%/cn.nexusflow.desktop/</code> into the Windows File Explorer address bar and press Enter.</p></div><h3 id="ue-plugin-logs" tabindex="-1">UE Plugin Logs <a class="header-anchor" href="#ue-plugin-logs" aria-label="Permalink to &quot;UE Plugin Logs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Log</th><th>Path</th></tr></thead><tbody><tr><td>UE Editor log</td><td><code>&lt;UE Project Directory&gt;/Saved/Logs/*.log</code></td></tr><tr><td>Bridge debug log (Debug builds)</td><td><code>&lt;UE Project Directory&gt;/Saved/Logs/nexusflow_bridge_debug.log</code></td></tr></tbody></table><ul><li>Search for the keyword <strong><code>LogNexusFlow</code></strong> in UE logs to filter NexusFlow plugin entries</li><li>The Bridge debug log is only generated in Debug builds. In Release builds, Bridge output is merged into the standard UE log — search for <strong><code>[Bridge]</code></strong></li></ul><h2 id="nexusflow-setup-dialog-in-ue" tabindex="-1">NexusFlow Setup Dialog in UE <a class="header-anchor" href="#nexusflow-setup-dialog-in-ue" aria-label="Permalink to &quot;NexusFlow Setup Dialog in UE&quot;">​</a></h2><p><strong>Symptom</strong>: A &quot;NexusFlow Setup&quot; dialog pops up every time UE starts.</p><p><strong>Explanation</strong>: This dialog appears when the NexusFlow plugin detects that the desktop app is not installed or the embedding model is not ready. It&#39;s a first-run helper, not an error.</p><p><strong>Options</strong>:</p><table tabindex="0"><thead><tr><th>What you want</th><th>Action</th></tr></thead><tbody><tr><td>Set it up now</td><td>Click <strong>Download Model</strong> or <strong>Open Settings</strong> and follow the prompts</td></tr><tr><td>Set it up later</td><td>Click <strong>Later</strong> — the dialog will appear again on next startup</td></tr><tr><td>Never see it again</td><td>Click <strong>Don&#39;t Show Again</strong> — the dialog won&#39;t appear anymore</td></tr></tbody></table><p><strong>To re-enable the dialog after dismissing it</strong>:</p><ol><li>Open <code>%LOCALAPPDATA%/NexusFlow/config.json</code></li><li>Change <code>&quot;showSetupWizard&quot;</code> to <code>true</code></li><li>Restart the UE Editor</li></ol><h2 id="still-stuck" tabindex="-1">Still stuck? <a class="header-anchor" href="#still-stuck" aria-label="Permalink to &quot;Still stuck?&quot;">​</a></h2><p>If none of the above steps resolved your issue:</p><ol><li>Collect the relevant log files (NexusFlow log + UE log)</li><li>Write down the exact steps to reproduce the problem</li><li>Open an issue on <a href="https://github.com/maxzhao/NexusFlow/issues" target="_blank" rel="noreferrer">GitHub Issues</a> with this information attached</li></ol>',55)])])}const p=o(s,[["render",a]]);export{h as __pageData,p as default};
